import{_ as a,c as r,o as l,ah as e}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/安全工具/netbird-安全工具.md","filePath":"github汇总/安全工具/netbird-安全工具.md"}'),t={name:"github汇总/安全工具/netbird-安全工具.md"};function s(n,i,o,h,d,g){return l(),r("div",null,i[0]||(i[0]=[e('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>NetBird</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>netbirdio</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>安全工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>传统VPN配置复杂，需要打开端口、配置防火墙规则，且缺乏细粒度的访问控制</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>将无配置的点对点专用网络和集中式访问控制系统结合</li><li>基于WireGuard的覆盖网络，自动连接机器</li><li>无需打开端口、复杂防火墙规则、VPN网关</li><li>细粒度访问策略，直观管理</li><li>SSO &amp; MFA支持、访问控制（组和规则）、活动日志</li><li>设备状态检查、IdP集成、私有DNS</li><li>支持Linux、Mac、Windows、Android、iOS、OpenWRT、Docker等几乎所有平台</li><li>有NetBird Cloud可以直接使用，也支持自托管</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>无配置，使用简单</li><li>基于WireGuard，安全高效</li><li>细粒度访问控制</li><li>企业级特性（SSO、MFA、审计日志等）</li><li>跨平台支持，几乎所有平台都支持</li><li>有云服务可以直接使用，也支持自托管</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/netbirdio/netbird" target="_blank" rel="noreferrer">https://github.com/netbirdio/netbird</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于想使用NetBird Cloud的普通用户，或想自托管的有Docker和Linux使用经验的用户</p><h2 id="前置条件检查-自托管" tabindex="-1">前置条件检查（自托管） <a class="header-anchor" href="#前置条件检查-自托管" aria-label="Permalink to “前置条件检查（自托管）”">​</a></h2><ol><li><p><strong>Docker检查</strong></p><ul><li>步骤目标：确认已安装Docker和Docker Compose</li><li>执行位置：本机终端</li><li>完整命令：<code>docker --version</code> 和 <code>docker-compose --version</code></li><li>成功标志：显示Docker和Docker Compose版本号</li><li>失败处理：访问 <a href="https://www.docker.com/" target="_blank" rel="noreferrer">Docker官网</a> 安装</li></ul></li><li><p><strong>基础设施要求</strong></p><ul><li>步骤目标：确认基础设施满足要求</li><li>执行位置：无</li><li>操作说明：需要Linux VM（至少1CPU、2GB内存）、公网IP、公网域名、TCP 80/443和UDP 3478端口开放</li><li>成功标志：基础设施满足要求</li><li>失败处理：准备符合要求的基础设施</li></ul></li></ol><h2 id="主路径-使用netbird-cloud-推荐" tabindex="-1">主路径：使用NetBird Cloud（推荐） <a class="header-anchor" href="#主路径-使用netbird-cloud-推荐" aria-label="Permalink to “主路径：使用NetBird Cloud（推荐）”">​</a></h2><h3 id="步骤1-下载安装" tabindex="-1">步骤1：下载安装 <a class="header-anchor" href="#步骤1-下载安装" aria-label="Permalink to “步骤1：下载安装”">​</a></h3><ul><li><strong>步骤目标</strong>：下载并安装NetBird</li><li><strong>执行位置</strong>：浏览器</li><li><strong>操作说明</strong>：访问 <a href="https://app.netbird.io/install" target="_blank" rel="noreferrer">https://app.netbird.io/install</a> 下载安装对应平台的客户端</li><li><strong>成功标志</strong>：客户端安装完成</li><li><strong>失败处理</strong>：参考官方安装文档</li></ul><h3 id="步骤2-注册登录" tabindex="-1">步骤2：注册登录 <a class="header-anchor" href="#步骤2-注册登录" aria-label="Permalink to “步骤2：注册登录”">​</a></h3><ul><li><strong>步骤目标</strong>：注册并登录NetBird</li><li><strong>执行位置</strong>：NetBird客户端</li><li><strong>操作说明</strong>：使用Google、Microsoft、GitHub或邮箱注册登录</li><li><strong>成功标志</strong>：登录成功</li><li><strong>失败处理</strong>：检查网络连接</li></ul><h3 id="步骤3-添加机器" tabindex="-1">步骤3：添加机器 <a class="header-anchor" href="#步骤3-添加机器" aria-label="Permalink to “步骤3：添加机器”">​</a></h3><ul><li><strong>步骤目标</strong>：添加更多机器到网络</li><li><strong>执行位置</strong>：NetBird管理界面</li><li><strong>操作说明</strong>：在管理界面添加更多机器</li><li><strong>成功标志</strong>：机器添加成功</li><li><strong>失败处理</strong>：参考官方文档</li></ul><h2 id="备选部署路径-自托管" tabindex="-1">备选部署路径：自托管 <a class="header-anchor" href="#备选部署路径-自托管" aria-label="Permalink to “备选部署路径：自托管”">​</a></h2><h3 id="步骤1-运行安装脚本" tabindex="-1">步骤1：运行安装脚本 <a class="header-anchor" href="#步骤1-运行安装脚本" aria-label="Permalink to “步骤1：运行安装脚本”">​</a></h3><ul><li><strong>步骤目标</strong>：运行自托管安装脚本</li><li><strong>执行位置</strong>：Linux服务器终端</li><li><strong>完整命令</strong>：<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NETBIRD_DOMAIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">netbird.example.com; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/netbirdio/netbird/releases/latest/download/getting-started.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div></li><li><strong>成功标志</strong>：脚本执行完成</li><li><strong>失败处理</strong>：检查网络连接，确认域名和服务器配置</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li><strong>检查方式</strong>：访问NetBird管理界面</li><li><strong>预期返回</strong>：管理界面正常显示，可以管理机器和访问策略</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>现象</strong>：机器无法连接</p><ul><li><strong>可能原因</strong>：网络问题、防火墙限制</li><li><strong>解决步骤</strong>：检查网络连接，确认防火墙开放必要端口</li></ul></li><li><p><strong>现象</strong>：自托管安装失败</p><ul><li><strong>可能原因</strong>：基础设施不满足要求</li><li><strong>解决步骤</strong>：确认基础设施满足要求</li></ul></li><li><p><strong>现象</strong>：访问策略不生效</p><ul><li><strong>可能原因</strong>：策略配置错误</li><li><strong>解决步骤</strong>：检查访问策略配置</li></ul></li></ol><h2 id="官方文档与补充入口" tabindex="-1">官方文档与补充入口 <a class="header-anchor" href="#官方文档与补充入口" aria-label="Permalink to “官方文档与补充入口”">​</a></h2><p>项目地址：<a href="https://github.com/netbirdio/netbird" target="_blank" rel="noreferrer">https://github.com/netbirdio/netbird</a> <a href="/网络环境.html">海外网络环境配置 →</a> 官方文档：<a href="https://docs.netbird.io" target="_blank" rel="noreferrer">https://docs.netbird.io</a> NetBird Cloud：<a href="https://app.netbird.io" target="_blank" rel="noreferrer">https://app.netbird.io</a></p>',37)]))}const b=a(t,[["render",s]]);export{p as __pageData,b as default};
